#include<bits/stdc++.h>
using namespace std;
struct student{
	int c,m,e,num,sum;
}a[1145];int n;
bool cmp(student a,student b){
	if(a.sum!=b.sum)return (a.sum>b.sum);
	if(a.c!=b.c)return (a.c>b.c);
	return (a.num<b.num);
}
int main(void){
	cin>>n;
	for(int i=1;i<=n;i++){
		cin>>a[i].c>>a[i].m>>a[i].e;
		a[i].sum=a[i].c+a[i].m+a[i].e;
		a[i].num=i;
	}
	sort(a+1,a+n+1,cmp);
	for(int i=1;i<6;i++){
		cout<<a[i].num<<' '<<a[i].sum<<'\n';
	}
	return false;
}
